"use client";

import { Separator } from "@base-ui/react/separator";
import { CpuIcon, DashboardSquare01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { ConnectionIndicator, useConnectionStore } from "@/features/connect-server";
import { HotkeyDisplay } from "@/features/push-to-talk";

export function StatusBar() {
	const gpuInfo = useConnectionStore((s) => s.gpuInfo);
	const currentModel = useConnectionStore((s) => s.currentModel);

	return (
		<div className="flex shrink-0 items-center justify-between border-border border-t bg-surface-primary px-3 py-1.5 font-mono">
			<div className="flex items-center gap-3">
				<ConnectionIndicator />
				{gpuInfo && (
					<span className="flex items-center gap-1.5 text-[11px] text-foreground-dim">
						<HugeiconsIcon
							color={gpuInfo.available ? "var(--color-success)" : "var(--color-error)"}
							icon={CpuIcon}
							size={12}
						/>
						{gpuInfo.name}
					</span>
				)}
			</div>
			<div className="flex items-center gap-2">
				<HotkeyDisplay />
				{currentModel && (
					<>
						<Separator className="h-3 w-px bg-border" orientation="vertical" />
						<span className="flex items-center gap-1.5 text-[11px] text-foreground-dim">
							<HugeiconsIcon
								color="var(--color-foreground-dim)"
								icon={DashboardSquare01Icon}
								size={12}
							/>
							{currentModel}
						</span>
					</>
				)}
			</div>
		</div>
	);
}
