"use client";

import { useVisualizerStore } from "../model/visualizer-store";

const BAR_COUNT = 40;

export function WaveformBars() {
	const frequencyData = useVisualizerStore((s) => s.frequencyData);
	const isActive = useVisualizerStore((s) => s.isActive);

	const bars = Array.from({ length: BAR_COUNT }, (_, i) => {
		const value = frequencyData[i] ?? 0;
		const height = isActive ? Math.max(3, (value / 255) * 100) : 3;
		return height;
	});

	return (
		<div className="flex w-full items-end justify-center gap-px" style={{ height: "48px" }}>
			{bars.map((height, i) => {
				const centerDistance = Math.abs(i - BAR_COUNT / 2) / (BAR_COUNT / 2);
				const baseOpacity = isActive ? 0.4 + (1 - centerDistance) * 0.6 : 0.15;

				return (
					<div
						key={`bar-${i}`}
						style={{
							width: "3px",
							height: `${height}%`,
							borderRadius: "1px",
							backgroundColor: isActive ? "var(--color-accent)" : "var(--color-border)",
							transition: "height 80ms ease-out",
							opacity: baseOpacity,
						}}
					/>
				);
			})}
		</div>
	);
}
