"use client";

import { Mic01Icon, MicOff01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { WaveformBars } from "@/features/audio-visualizer";
import { useHotkeyStore } from "@/features/push-to-talk";
import { Kbd, KbdGroup } from "@/shared/ui/kbd";

function parseAccelerator(accelerator: string): string[] {
	return accelerator.split("+").map((key) => {
		switch (key) {
			case "Control":
				return "Ctrl";
			case "Meta":
				return "Win";
			default:
				return key;
		}
	});
}

export function AudioDisplay() {
	const isPressed = useHotkeyStore((s) => s.isPressed);
	const accelerator = useHotkeyStore((s) => s.accelerator);
	const keys = parseAccelerator(accelerator);

	return (
		<div
			className={`relative flex shrink-0 flex-col items-center justify-center gap-2 overflow-hidden rounded-lg bg-surface-secondary px-4 py-5 transition-[border-color,box-shadow] duration-300 ease-in-out ${isPressed ? "border border-border-accent shadow-glow" : "border border-border"}`}
		>
			{/* Subtle glow backdrop when recording */}
			{isPressed && (
				<div
					className="pointer-events-none absolute inset-0"
					style={{
						background:
							"radial-gradient(ellipse at center, rgba(245,158,11,0.04) 0%, transparent 70%)",
					}}
				/>
			)}

			<WaveformBars />

			<div className="flex items-center gap-2">
				<HugeiconsIcon
					color={isPressed ? "var(--color-accent)" : "var(--color-foreground-dim)"}
					icon={isPressed ? Mic01Icon : MicOff01Icon}
					size={14}
				/>
				{isPressed ? (
					<span className="animate-recording-pulse-slow font-medium font-mono text-[13px] text-accent">
						RECORDING
					</span>
				) : (
					<span className="flex items-center gap-1.5">
						<span className="font-medium font-mono text-[13px] text-foreground-muted">PRESS</span>
						<KbdGroup>
							{keys.map((key) => (
								<Kbd key={key}>{key}</Kbd>
							))}
						</KbdGroup>
					</span>
				)}
			</div>
		</div>
	);
}
